-weight:700">过往与外貌</div><div class="kv-row"><span style="color:var(--muted)">过往经历</span><span class="kv-v">'+past+'</span></div><div class="kv-row"><span style="color:var(--muted)">容貌身材</span><span class="kv-v">'+look+'</span></div></div><div class="ns-title">关系与看法</div><div class="text-block"><div class="kv-row"><span style="color:var(--muted)">对主角看法</span><span class="kv-v" style="font-style:italic;color:var(--gold)">"'+(rel.对主角看法||'-')+'"</span></div><div class="kv-row" style="margin-top:8px;border-top:1px dashed var(--border);padding-top:8px"><span style="color:var(--muted)">好感 / 信任 / 修罗场</span><span class="kv-v"><span style="color:var(--pink)">'+favor+'</span> / <span style="color:var(--green)">'+trust+'</span> / <span style="color:var(--danger)">'+chaos+'</span></span></div></div><div class="ns-title">当前着装</div>'+eqHtml+'<div class="ns-title">背包</div>'+(invHtml||'<div style="font-size:12px;color:var(--muted);text-align:center;padding:8px">背包为空</div>')+'<div class="ns-title pink">私密档案</div><div class="text-block"><div class="kv-row"><span style="color:var(--muted)">发情度 / 常识崩坏度</span><span class="kv-v"><span style="color:var(--danger)">'+(secret.发情度||0)+'</span> / <span style="color:var(--pink)">'+(secret.常识崩坏度||0)+'</span></span></div><div class="kv-row"><span style="color:var(--muted)">体温 / 体液分泌</span><span class="kv-v">'+(secret.体温||'-')+' / '+(secret.体液分泌||'-')+'</span></div><div class="kv-row"><span style="color:var(--muted)">身体反应</span><span class="kv-v">'+(secret.身体反应||'-')+'</span></div><div class="kv-row"><span style="color:var(--muted)">隐藏性癖</span><span class="kv-v" style="color:var(--pink)">'+(secret.隐藏性癖||'-')+'</span></div><div class="kv-row"><span style="color:var(--muted)">生理周期 / 受孕率</span><span class="kv-v">'+(secret.生理周期||'-')+' / '+(secret.受孕概率||0)+'%</span></div></div><div class="ns-title pink">器官状态</div><div class="npc-grid">'+partsHtml+'</div></div></div>'}nc.innerHTML=html}

